import { Transition, Spring, config } from "react-spring/renderprops";
import { useState, useCallback, useEffect, useRef } from "react";

import "./about_me.css";
import profilePic from "./circle_photo.jpeg";

export default function AboutMe({ collapse }) {
  const letters = "Hi, I'm Andrew";
  const lastname = " Dotterer";
  const titlesObj = [
    { title: "Software Engineer", key: "softwareEngineer" },
    { title: "Oboist", key: "oboist" },
  ];

  const [titles, setTitles] = useState([{}]);
  const [greetingMsg, setGreetingMsg] = useState([{}]);
  const [aboutMe_bottom_style, setAboutMe_bottom_style] = useState({
    flewGrow: 2,
  });

  const [springFromStyle, setSpringFromStyle] = useState({});
  const [aboutMe_container_style, setAboutMe_container_style] = useState({});
  const [profile_pic_style, setProfile_pic_style] = useState({});
  const [greeting_style, styleGreeting_style] = useState({});

  // const break_Ref = useRef(null);
  // const executeScroll = () => break_Ref.current.scroll();

  useEffect(() => {
    if (springFromStyle) {
      setTimeout(() => {
        setSpringFromStyle({ width: "18vw", height: "18vw" });
      }, 10);
    }

    if (greetingMsg) {
      for (let i = 0; i < letters.length; i++) {
        setTimeout(() => {
          setGreetingMsg((x) => {
            return [...x, { key: `${i}-${letters[i]}`, text: letters[i] }];
          });
        }, 100 * i);
      }
    }
  }, []);

  useEffect(() => {
    if (
      greetingMsg.length > letters.length &&
      greeting_style.fontSize !== "2rem"
    ) {
      setTimeout(() => {
        for (let i = 0; i < letters.length - 6; i++) {
          // JUST GET MY NAME
          setTimeout(() => {
            setGreetingMsg((x) => {
              return x.slice(1);
            });
          }, 120 * i);
        }
        setTimeout(() => {
          setAboutMe_bottom_style({ height: "75vh" });
          setAboutMe_container_style({ height: "19vh" });
          setSpringFromStyle({ width: "13vh", height: "13vh" });
          setProfile_pic_style({
            width: "11rem",
          });
          setTimeout(() => {
            styleGreeting_style({ fontSize: "2rem" });
          }, 400);
        }, 100);
      }, 1150);
    }
  }, [greetingMsg, greeting_style]);

  useEffect(() => {
    if (greeting_style.fontSize === "2rem") {
      for (let i = 0; i < lastname.length; i++) {
        setTimeout(() => {
          setGreetingMsg((x) => {
            return [...x, { key: `${i}-${lastname[i]}`, text: lastname[i] }];
          });
        }, 100 * i);
      }
      if (aboutMe_bottom_style.height === "75vh") {
        setTimeout(() => {
          titlesObj.forEach((titleObj, i) => {
            setTimeout(() => {
              setTitles((state) => [...state, titleObj]);
            }, 850 * i);
          });
        }, 400);
      }
    }
  }, [greeting_style, aboutMe_bottom_style]);

  useEffect(() => {
    if (!collapse) return;
    for (let i = 0; i < titles.length; i++) {
      setTimeout(() => {
        setTitles((x) => {
          return x.slice(1);
        });
      }, 200);
    }

    // setTimeout(executeScroll, 1000);
  }, [collapse]);
  // useEffect(() => {
  //   if (aboutMe_bottom_style.height === "75vh") {
  //     titlesObj.forEach((titleObj, i) => {
  //       setTimeout(() => {
  //         setTitles((state) => [...state, titleObj]);
  //       }, 2000 * i);
  //     });
  //   }
  // }, [aboutMe_bottom_style]);

  return (
    <>
      <div style={aboutMe_container_style} className="div__aboutMe_container">
        <div style={profile_pic_style} className="div__profile_pic">
          <img style={springFromStyle} src={profilePic} alt="profile" />
        </div>
        <div style={greeting_style} className="div__greeting">
          <Transition
            config={config.default}
            items={greetingMsg}
            keys={(item) => item.key}
            from={{
              transitionDuration: "130ms",
              transform: `translate3d(0,-50rem,0)`,
            }}
            enter={{
              transform: "translate3d(0,0px,0)",
              transitionDuration: "200ms",
            }}
            leave={{
              delay: "390ms",
              transitionDuration: "200ms",
              transform: "translate3d(0,-40rem,0)",
            }}
          >
            {(item) => (props) => <span style={props}>{item.text}</span>}
          </Transition>
        </div>
      </div>

      <div style={aboutMe_bottom_style} className="div__aboutMe_bottom">
        <Transition
          config={config.default}
          items={titles}
          keys={(item) => item.key}
          from={{
            opacity: 0.1,
            transition: "all 0.25s linear",
            transform: `translate3d(-100vw,0,0)`,
          }}
          enter={{
            opacity: 1,
            fontSize: "1rem",
            transitionDuration: "500ms",
            transform: "translate3d(0,0px,0)",
          }}
          leave={{
            opacity: 0,
            fontSize: "1px",
            transitionDuration: "500ms",
            transform: "translate3d(110%,0,0)",
          }}
        >
          {(item) => (props) => (
            <div style={props}>
              <h1>{item.title}</h1>
            </div>
          )}
        </Transition>
      </div>
      <br />
    </>
  );
}
